import React, { useState, useEffect } from 'react';
import { profileApi, publicationApi } from '../../api';
import toast from 'react-hot-toast';
import {
  Users, FileText, CheckCircle, XCircle, MessageSquare,
  TrendingUp, Award, Clock, BarChart2
} from 'lucide-react';

const PRE_QUAL_THRESHOLD = 50;

const STAGE_META = {
  IDEA:   { label: 'Idée',       color: '#8b5cf6' },
  MVP:    { label: 'MVP',        color: '#3b82f6' },
  GROWTH: { label: 'Croissance', color: '#f59e0b' },
  SCALE:  { label: 'Scale',      color: '#10b981' },
};

export default function CMDashboard() {
  const [pendingProfiles, setPendingProfiles] = useState([]);
  const [approvedProfiles, setApprovedProfiles] = useState([]);
  const [pendingPubs, setPendingPubs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState('profiles');

  const [validating, setValidating] = useState(null);
  const [validationForm, setValidationForm] = useState({ action: '', reason: '' });
  const [archiving, setArchiving] = useState(null);
  const [archiveReason, setArchiveReason] = useState('');

  useEffect(() => { loadData(); }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [pendRes, approvedRes, pubsRes] = await Promise.all([
        profileApi.getPending(),
        profileApi.getApproved(),
        publicationApi.getPending(),
      ]);
      setPendingProfiles(pendRes.data);
      setApprovedProfiles(approvedRes.data);
      setPendingPubs(pubsRes.data);
    } catch {
      toast.error('Erreur de chargement.');
    } finally {
      setLoading(false);
    }
  };

  const handleValidate = async (profileId) => {
    if (!validationForm.action) { toast.error('Choisissez une action.'); return; }
    if ((validationForm.action === 'REJECT' || validationForm.action === 'REQUEST_INFO')
        && !validationForm.reason.trim()) {
      toast.error('Une explication est obligatoire.');
      return;
    }
    try {
      await profileApi.validate(profileId, validationForm);
      toast.success('Décision enregistrée.');
      setValidating(null);
      setValidationForm({ action: '', reason: '' });
      loadData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Erreur.');
    }
  };

  const handleApprovePub = async (id) => {
    try {
      await publicationApi.approve(id);
      toast.success('Publication approuvée. +5 pts attribués à l\'auteur.');
      loadData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Erreur.');
    }
  };

  const handleArchivePub = async (id) => {
    if (!archiveReason.trim()) { toast.error('La raison d\'archivage est obligatoire.'); return; }
    try {
      await publicationApi.archive(id, archiveReason);
      toast.success('Publication archivée.');
      setArchiving(null);
      setArchiveReason('');
      loadData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Erreur.');
    }
  };

  // ── Computed stats ─────────────────────────────────────────────────────────
  const total = approvedProfiles.length;
  const preQualified = approvedProfiles.filter(p => p.intelligenceScore >= PRE_QUAL_THRESHOLD).length;
  const avgScore = total > 0
    ? Math.round(approvedProfiles.reduce((sum, p) => sum + (p.intelligenceScore || 0), 0) / total)
    : 0;

  const bySector = approvedProfiles.reduce((acc, p) => {
    const s = p.businessSector || 'Non renseigné';
    acc[s] = (acc[s] || 0) + 1;
    return acc;
  }, {});
  const sectorEntries = Object.entries(bySector).sort((a, b) => b[1] - a[1]).slice(0, 6);
  const sectorMax = sectorEntries[0]?.[1] || 1;

  const byStage = approvedProfiles.reduce((acc, p) => {
    const s = p.developmentStage || 'IDEA';
    acc[s] = (acc[s] || 0) + 1;
    return acc;
  }, {});

  return (
    <div className="page-container">
      <div className="page-header">
        <h1 className="page-title">Tableau de bord — Community Manager</h1>
        <p className="page-subtitle">Gestion de la qualité et de l'intégrité de la communauté</p>
      </div>

      {/* ── KPI row ─────────────────────────────────────────────────────────── */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 14, marginBottom: 20 }}>
        <KpiCard icon={Users}     label="Startups approuvées"    value={total}         color="#16a34a" />
        <KpiCard icon={Clock}     label="Profils en attente"     value={pendingProfiles.length} color="#c8102e" />
        <KpiCard icon={TrendingUp} label="Score moyen"           value={`${avgScore} pts`} color="#3b82f6" />
        <KpiCard icon={Award}     label="Pré-qualifiées (≥ 50)"  value={preQualified}  color="#f59e0b" />
      </div>

      {/* ── Startup statistics ──────────────────────────────────────────────── */}
      {!loading && total > 0 && (
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14, marginBottom: 24 }}>

          {/* Sector breakdown */}
          <div className="card" style={{ padding: '20px 22px' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 16 }}>
              <BarChart2 size={15} color="#6b7280" />
              <span style={{ fontSize: 13, fontWeight: 700, color: '#374151' }}>Répartition par secteur</span>
            </div>
            {sectorEntries.length === 0 ? (
              <p style={{ fontSize: 12, color: '#9ca3af' }}>Aucune donnée.</p>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                {sectorEntries.map(([sector, count]) => (
                  <div key={sector}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                      <span style={{ fontSize: 12, color: '#374151', fontWeight: 500 }}>{sector}</span>
                      <span style={{ fontSize: 12, fontWeight: 700, color: '#6b7280' }}>{count}</span>
                    </div>
                    <div style={{ height: 6, background: '#f3f4f6', borderRadius: 4, overflow: 'hidden' }}>
                      <div style={{
                        height: '100%',
                        width: `${(count / sectorMax) * 100}%`,
                        background: '#c8102e',
                        borderRadius: 4,
                        transition: 'width 0.4s ease',
                      }} />
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Stage breakdown */}
          <div className="card" style={{ padding: '20px 22px' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 16 }}>
              <TrendingUp size={15} color="#6b7280" />
              <span style={{ fontSize: 13, fontWeight: 700, color: '#374151' }}>Répartition par stade</span>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              {Object.entries(STAGE_META).map(([key, { label, color }]) => {
                const count = byStage[key] || 0;
                const pct = total > 0 ? Math.round((count / total) * 100) : 0;
                return (
                  <div key={key}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                        <div style={{ width: 10, height: 10, borderRadius: '50%', background: color }} />
                        <span style={{ fontSize: 12, color: '#374151', fontWeight: 500 }}>{label}</span>
                      </div>
                      <span style={{ fontSize: 12, fontWeight: 700, color: '#6b7280' }}>
                        {count} <span style={{ fontWeight: 400, color: '#9ca3af' }}>({pct}%)</span>
                      </span>
                    </div>
                    <div style={{ height: 6, background: '#f3f4f6', borderRadius: 4, overflow: 'hidden' }}>
                      <div style={{
                        height: '100%',
                        width: `${pct}%`,
                        background: color,
                        borderRadius: 4,
                        transition: 'width 0.4s ease',
                      }} />
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Score distribution */}
            <div style={{ marginTop: 18, paddingTop: 16, borderTop: '1px solid #f3f4f6' }}>
              <div style={{ fontSize: 12, fontWeight: 700, color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 10 }}>
                Score d'intelligence
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 8 }}>
                {[
                  { label: '< 25 pts', filter: p => p.intelligenceScore < 25, color: '#ef4444' },
                  { label: '25–49 pts', filter: p => p.intelligenceScore >= 25 && p.intelligenceScore < 50, color: '#f59e0b' },
                  { label: '≥ 50 pts', filter: p => p.intelligenceScore >= 50, color: '#16a34a' },
                ].map(({ label, filter, color }) => {
                  const n = approvedProfiles.filter(filter).length;
                  return (
                    <div key={label} style={{
                      textAlign: 'center', background: color + '12',
                      borderRadius: 8, padding: '10px 6px',
                    }}>
                      <div style={{ fontSize: 20, fontWeight: 800, color }}>{n}</div>
                      <div style={{ fontSize: 10, color: '#6b7280', marginTop: 2 }}>{label}</div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ── Moderation tabs ─────────────────────────────────────────────────── */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
        {[
          { key: 'profiles', label: `Profils à valider (${pendingProfiles.length})` },
          { key: 'pubs',     label: `Publications (${pendingPubs.length})` },
        ].map(t => (
          <button key={t.key} className={`btn btn-sm ${tab === t.key ? 'btn-primary' : 'btn-ghost'}`}
            onClick={() => setTab(t.key)}>{t.label}</button>
        ))}
      </div>

      {loading ? <p style={{ color: 'var(--color-ink-muted)' }}>Chargement…</p> : (

        tab === 'profiles' ? (
          pendingProfiles.length === 0 ? (
            <div className="empty-state">
              <CheckCircle size={40} />
              <p>Aucun profil en attente de validation.</p>
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              {pendingProfiles.map(profile => (
                <div key={profile.id} className="card">
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 14 }}>
                    <div>
                      <h3 style={{ fontSize: 17, fontWeight: 700 }}>
                        {profile.companyName || 'Profil #' + profile.id.slice(-6)}
                      </h3>
                      <div style={{ display: 'flex', gap: 12, marginTop: 6, flexWrap: 'wrap' }}>
                        {profile.businessSector && <Tag label={profile.businessSector} />}
                        {profile.developmentStage && <Tag label={profile.developmentStage} />}
                        {profile.location && <Tag label={profile.location} />}
                      </div>
                    </div>
                    {!profile.isSufficientlyComplete && (
                      <span className="badge badge-rejected">Profil incomplet</span>
                    )}
                  </div>

                  {profile.companyDescription && (
                    <p style={{ fontSize: 14, color: 'var(--color-ink-muted)', marginBottom: 12, lineHeight: 1.5 }}>
                      {profile.companyDescription}
                    </p>
                  )}

                  {profile.priorityNeeds?.length > 0 && (
                    <div style={{ marginBottom: 14 }}>
                      <span style={{ fontSize: 12, fontWeight: 700, color: 'var(--color-ink-muted)', textTransform: 'uppercase' }}>Besoins : </span>
                      {profile.priorityNeeds.map(n => <Tag key={n} label={n} />)}
                    </div>
                  )}

                  {validating === profile.id ? (
                    <div style={{
                      background: 'var(--color-surface)',
                      border: '1px solid var(--color-border)',
                      borderRadius: 'var(--radius-md)',
                      padding: 16,
                      marginTop: 4,
                    }}>
                      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
                        {[
                          { value: 'APPROVE',      label: 'Valider',            icon: CheckCircle },
                          { value: 'REJECT',       label: 'Rejeter',            icon: XCircle },
                          { value: 'REQUEST_INFO', label: 'Demander des infos', icon: MessageSquare },
                        ].map(({ value, label, icon: Icon }) => (
                          <button
                            key={value}
                            className={`btn btn-sm ${validationForm.action === value ? 'btn-primary' : 'btn-ghost'}`}
                            onClick={() => setValidationForm(f => ({ ...f, action: value }))}
                          >
                            <Icon size={13} /> {label}
                          </button>
                        ))}
                      </div>

                      {(validationForm.action === 'REJECT' || validationForm.action === 'REQUEST_INFO') && (
                        <div className="form-group">
                          <label className="form-label">
                            {validationForm.action === 'REJECT' ? 'Motif de rejet *' : 'Informations demandées *'}
                          </label>
                          <textarea className="form-textarea" style={{ minHeight: 80 }}
                            value={validationForm.reason}
                            onChange={e => setValidationForm(f => ({ ...f, reason: e.target.value }))}
                            placeholder={validationForm.action === 'REJECT'
                              ? 'Expliquez la raison du rejet…'
                              : 'Précisez les informations supplémentaires requises…'}
                          />
                        </div>
                      )}

                      <div style={{ display: 'flex', gap: 8 }}>
                        <button className="btn btn-primary btn-sm" onClick={() => handleValidate(profile.id)}>
                          Confirmer
                        </button>
                        <button className="btn btn-ghost btn-sm" onClick={() => {
                          setValidating(null);
                          setValidationForm({ action: '', reason: '' });
                        }}>Annuler</button>
                      </div>
                    </div>
                  ) : (
                    <button className="btn btn-secondary btn-sm"
                      onClick={() => setValidating(profile.id)} style={{ marginTop: 4 }}>
                      Traiter ce profil
                    </button>
                  )}
                </div>
              ))}
            </div>
          )
        ) : (
          pendingPubs.length === 0 ? (
            <div className="empty-state">
              <CheckCircle size={40} />
              <p>Aucune publication en attente.</p>
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              {pendingPubs.map(pub => (
                <div key={pub.id} className="card">
                  <div style={{ marginBottom: 12 }}>
                    {pub.sector && <Tag label={pub.sector} />}
                    <h3 style={{ fontSize: 17, fontWeight: 700, margin: '6px 0 4px' }}>{pub.title}</h3>
                    <p style={{ fontSize: 13, color: 'var(--color-ink-muted)' }}>Par {pub.authorName}</p>
                  </div>

                  <p style={{ fontSize: 14, lineHeight: 1.65, marginBottom: 14 }}>
                    {pub.content.length > 400 ? pub.content.substring(0, 400) + '…' : pub.content}
                  </p>

                  {archiving === pub.id ? (
                    <div style={{ background: 'var(--color-surface)', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-md)', padding: 14 }}>
                      <div className="form-group">
                        <label className="form-label">Raison d'archivage * (notifiée à l'auteur)</label>
                        <textarea className="form-textarea" style={{ minHeight: 70 }}
                          value={archiveReason}
                          onChange={e => setArchiveReason(e.target.value)}
                          placeholder="Expliquez pourquoi ce contenu est archivé…" />
                      </div>
                      <div style={{ display: 'flex', gap: 8 }}>
                        <button className="btn btn-danger btn-sm" onClick={() => handleArchivePub(pub.id)}>
                          Confirmer l'archivage
                        </button>
                        <button className="btn btn-ghost btn-sm" onClick={() => { setArchiving(null); setArchiveReason(''); }}>
                          Annuler
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div style={{ display: 'flex', gap: 8 }}>
                      <button className="btn btn-sm" style={{ background: 'var(--color-success)', color: 'white' }}
                        onClick={() => handleApprovePub(pub.id)}>
                        <CheckCircle size={13} /> Approuver
                      </button>
                      <button className="btn btn-ghost btn-sm" onClick={() => setArchiving(pub.id)}>
                        <XCircle size={13} /> Archiver
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )
        )
      )}
    </div>
  );
}

function KpiCard({ icon: Icon, label, value, color }) {
  return (
    <div className="card" style={{ display: 'flex', alignItems: 'center', gap: 14, padding: '16px 18px' }}>
      <div style={{
        width: 44, height: 44, flexShrink: 0,
        background: color + '18',
        borderRadius: 10,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
      }}>
        <Icon size={20} color={color} />
      </div>
      <div>
        <div style={{ fontSize: 24, fontWeight: 800, fontFamily: 'var(--font-display)', lineHeight: 1 }}>{value}</div>
        <div style={{ fontSize: 12, color: 'var(--color-ink-muted)', marginTop: 3 }}>{label}</div>
      </div>
    </div>
  );
}

function Tag({ label }) {
  return (
    <span style={{
      display: 'inline-block',
      padding: '2px 9px',
      background: 'var(--color-surface)',
      border: '1px solid var(--color-border)',
      borderRadius: 100,
      fontSize: 12,
      fontWeight: 600,
      color: 'var(--color-ink-muted)',
      marginRight: 5,
      marginBottom: 4,
    }}>{label}</span>
  );
}
